#include <stdio.h>
#include <stdlib.h>

void find_numbers(int S, int P, int k, int current_sum, int current_product, int* current_numbers, int current_index) {
    if (current_index == k) {
        if (current_sum == S && current_product == P) {
            for (int i = 0; i < k; i++) {
                printf("%d ", current_numbers[i]);
            }
            printf("\n");
            exit(0);
        }
        return;
    }
    for (int i = 1; i <= S; i++) {
        if (current_sum + i <= S && current_product * i <= P) {
            current_numbers[current_index] = i;
            find_numbers(S, P, k, current_sum + i, current_product * i, current_numbers, current_index + 1);
        }
    }
}

int main() {
    int S, P, k;
    scanf("%d %d %d", &S, &P, &k);
    int* current_numbers = (int*) malloc(k * sizeof(int));
    find_numbers(S, P, k, 0, 1, current_numbers, 0);
    printf("NO\n");
    free(current_numbers);
    return 0;
}

